import{_ as s,o as e,c as t,O as n}from"./chunks/framework.0d5b6918.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/orchestration.md","filePath":"en/product/orchestration.md","lastUpdated":1776439080000}'),i={name:"en/product/orchestration.md"};function r(l,a,c,o,p,d){return e(),t("div",null,a[0]||(a[0]=[n('<div class="brand-page-shell brand-page-shell--orchestration"><section class="brand-hero"><div><p class="brand-kicker">Orchestration</p><h1>Orchestration</h1><div class="brand-hero__panel"><span class="brand-pill">Roadmap After 2.0</span><strong>Capability orchestration is not part of the delivered <code>1.0 / 1.1</code> scope today. It becomes a formal product direction only after <code>2.0</code>.</strong><p>Only after trusted single-Skill execution is stable, and after the platform closes composite-request decomposition, node-level confirmation, formal fallback or rollback, and partial-success or recoverable states, should orchestration become a real product layer.</p></div><p class="brand-lead"> Orchestration is not about piling more buttons together. It is about taking multiple execution steps and turning them into one real working chain that still sits inside rules. </p><div class="brand-chip-list"><span class="brand-chip">multi-step execution</span><span class="brand-chip">parameter passing</span><span class="brand-chip">human confirmation</span><span class="brand-chip">result handoff</span><span class="brand-chip">full-chain trace</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="/en/contact.html#lead-form">Discuss capability onboarding</a><a class="cta-button" href="./capabilities.html">View core capabilities</a></div><div class="orchestration-signal-grid"><article class="brand-card brand-card--nested orchestration-signal-card"><p class="brand-kicker">Now</p><h3>Understand the product through the single-capability loop first</h3><p>The current platform can already complete the single-capability loop of identifying a need, recommending a capability, confirming execution, and returning a result in a stable way.</p></article><article class="brand-card brand-card--nested orchestration-signal-card"><p class="brand-kicker">Next</p><h3>Later extend into multi-step task chains</h3><p>The next step is not only step linking and parameter passing. It also includes composite-request decomposition, node-level confirmation, formal fallback or rollback, and partial-success or recoverable states.</p></article></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // ORCHESTRATION</span><span>DOC 04</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">step01</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;identify_need&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">step02</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;match_skill&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">step03</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;confirm_then_run&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">step04</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;pass_result_forward&#39;</span></span></div><div class="matrix-panel__callout">MULTI STEP / CONFIRMED / TRACEABLE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">now</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">single_step</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">next</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">multi_step</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">audit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">whole_chain</span></span></div></div><article class="brand-hero__panel orchestration-readiness-card"><span class="link-panel-label">Before Orchestration</span><strong>Before real multi-step orchestration, these 4 governance points need to be stable first</strong><p>Stringing several Skills together is not enough. Formal productization requires at least the following constraints and recovery capability.</p><div class="orchestration-readiness-list"><div class="orchestration-readiness-item"><span>Need decomposition</span><strong>Split a composite request into step nodes that can be confirmed</strong></div><div class="orchestration-readiness-item"><span>Node confirmation</span><strong>Higher-risk steps must still be able to stop and wait for human confirmation</strong></div><div class="orchestration-readiness-item"><span>Failure rollback</span><strong>The system must know where the chain failed and whether fallback or rollback is allowed</strong></div><div class="orchestration-readiness-item"><span>Chain trace</span><strong>The input, artifacts, and state of the whole task chain must remain traceable</strong></div></div></article></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Available Now</p><h2>What already exists today</h2><ul class="brand-list"><li>AI identifies the need</li><li>A Skill is recommended inside the permission boundary</li><li>Human confirmation exists</li><li>A single capability can execute</li><li>The result returns with audit traces kept</li></ul></article><article class="brand-card"><p class="brand-kicker">What It Adds</p><h2>What orchestration would add later</h2><ul class="brand-list"><li>One task splits into multiple steps</li><li>Multiple Skills or capability nodes execute in sequence</li><li>Parameters, results, or file references pass between steps</li><li>Higher-risk steps can require additional confirmation</li><li>The whole chain keeps logs, audit, and failure records</li></ul></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Best Fit</p><h2>Which scenarios fit orchestration</h2><ul class="brand-list"><li>Collect first, then clean, then generate a report</li><li>Read data first, then transform it, then write into a target system</li><li>Generate a result file first, then notify or archive</li><li>Organize multiple reusable capabilities into one stable task chain</li></ul></article><article class="brand-card"><p class="brand-kicker">Current Phase</p><h2>How to read the current phase correctly</h2><ul class="brand-list"><li>The platform already stabilizes trusted single-Skill execution</li><li>Multi-step orchestration is not a delivered <code>1.0 / 1.1</code> capability</li><li>Formal orchestration belongs to the product direction after <code>2.0</code></li><li>This path becomes valuable when a task needs multiple confirmations, parameter passing, file handoff, or cross-step tracking</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Summary</p><h2>One-sentence summary</h2><p class="brand-lead"> ExecFabric is first stabilizing <strong>trusted single-Skill execution</strong>. After the governance base is stronger, it can expand after <code>2.0</code> into a multi-step orchestration platform that remains confirmable, traceable, and auditable. </p></section></div>',1)]))}const _=s(i,[["render",r]]);export{h as __pageData,_ as default};
